/**
 * transactionApi.js
 * ─────────────────────────────────────────────────────────────
 * Funciones que consumen los endpoints de transacciones.
 * Separar las llamadas HTTP de los componentes facilita
 * el testing y reutilización.
 */

import axiosClient from './axiosClient'

/** @returns {{ success, count, data }} */
export const getTransactions = async (filters = {}) => {
  const { data } = await axiosClient.get('/transactions', { params: filters })
  return data
}

/** @returns {{ success, message, data }} */
export const createTransaction = async (payload) => {
  const { data } = await axiosClient.post('/transactions', payload)
  return data
}

/** @returns {{ success, message, data }} */
export const deleteTransaction = async (id) => {
  const { data } = await axiosClient.delete(`/transactions/${id}`)
  return data
}

/** @returns {{ success, data: { totalIncome, totalExpense, balance, byCategory, count }}} */
export const getSummary = async () => {
  const { data } = await axiosClient.get('/transactions/summary')
  return data
}
